<span class="line"><span style="color:#94E2D5;">            .</span><span style="color:#89B4FA;font-style:italic;">filter</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;">t</span><span style="color:#94E2D5;">|</span><span style="color:#89B4FA;font-style:italic;"> matches!</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">t</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">name</span><span style="color:#9399B2;">(),</span><span style="color:#A6E3A1;"> &quot;read_file&quot;</span><span style="color:#94E2D5;"> |</span><span style="color:#A6E3A1;"> &quot;grep&quot;</span><span style="color:#9399B2;">))</span></span>
